import React, { useEffect, useState, useRef } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  const texts = [
    "Hello", "Bonjour", "Ciao", "Hola", "こんにちは", "你好", "안녕하세요", "नमस्ते", "مرحبا"
  ];

  const [index, setIndex] = useState(0);
  const [selectedImage, setSelectedImage] = useState(null);
  const [hoveredId, setHoveredId] = useState(null);
  const [navbarHeight, setNavbarHeight] = useState(0);
  const [isAnyHovered, setIsAnyHovered] = useState(false);
  const [hoveredPosition, setHoveredPosition] = useState(null);

  const timeoutRef = useRef(null);
  const containerRef = useRef(null);
  const greenLineRef = useRef(null);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!isAnyHovered) {
        setIndex((prev) => (prev + 1) % texts.length);
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isAnyHovered]);

  useEffect(() => {
    const update = () => {
      const navbar = document.querySelector("nav");
      if (navbar) setNavbarHeight(navbar.offsetHeight);
    };
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);

  const images = [
    {
      id: 1,
      position: "left",
      url: "https://media.licdn.com/dms/image/v2/D4D22AQFq6-imvZP4iA/feedshare-shrink_2048_1536/feedshare-shrink_2048_1536/0/1687664122353",
      title: "Code QR",
      icon: "📱",
      description: "Une façon intelligente de passer commande sans attendre le serveur",
      fullDescription: "Le client scanne le code QR...",
      features: ["⚡ Scan rapide", "📱 Menu interactif", "🚀 Envoi direct"],
      explainText: "Expérience rapide et fluide sans attendre le serveur."
    },
    {
      id: 2,
      position: "center",
      url: "https://img.freepik.com/premium-photo/waiter-restaurant-generative-ai_900396-28345.jpg",
      title: "Le Serveur",
      icon: "👨‍🍳",
      description: "Gestion efficace et rapide des commandes",
      fullDescription: "Le serveur reçoit les commandes...",
      features: ["📍 Table", "💰 Prix", "📝 Remarques"],
      explainText: "Gestion intelligente des commandes."
    },
    {
      id: 3,
      position: "right",
      url: "https://png.pngtree.com/thumb_back/fw800/background/20221004/pngtree-closeup-of-100dollar-bill.jpg",
      title: "Facture",
      icon: "💰",
      description: "Calcul automatique",
      fullDescription: "Le système calcule automatiquement...",
      features: ["🧮 Total", "📊 Détails", "💳 Paiement"],
      explainText: "Facture rapide et précise."
    }
  ];

  const connectedGradient =
    "linear-gradient(180deg, #0a192f 0%, #1a365d 25%, #22543d 50%, #0a2f1a 75%, #000000 100%)";

  const handleMouseEnter = (id, position) => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    setHoveredId(id);
    setHoveredPosition(position);
    setIsAnyHovered(true);

    const container = containerRef.current;
    if (!container) return;
    const items = container.children;

    if (position === "left") {
      items[0].style.flex = "0 1 50%";
      items[1].style.flex = "0 0 25%";
      items[2].style.flex = "0 0 25%";
    } else if (position === "center") {
      items[0].style.flex = "0 0 20%";
      items[1].style.flex = "0 1 60%";
      items[2].style.flex = "0 0 20%";
    } else {
      items[0].style.flex = "0 0 25%";
      items[1].style.flex = "0 0 25%";
      items[2].style.flex = "0 1 50%";
    }
  };

  const handleMouseLeave = () => {
    timeoutRef.current = setTimeout(() => {
      setHoveredId(null);
      setHoveredPosition(null);
      setIsAnyHovered(false);

      const container = containerRef.current;
      if (!container) return;

      for (let item of container.children) {
        item.style.flex = "1";
      }
    }, 150);
  };

  const openModal = (image) => {
    setSelectedImage(image);
    document.body.style.overflow = "hidden";
  };

  const closeModal = () => {
    setSelectedImage(null);
    document.body.style.overflow = "auto";
  };

  const morphingStyle = `
    .morphing-bg {
      width: 100%;
      max-width: 1000px;
      min-height: 350px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 30px;
      padding: 40px;
      background: linear-gradient(45deg,#ee7752,#e73c7e,#23a6d5,#23d5ad);
      background-size: 400% 400%;
      animation: gradient 8s ease infinite, morph 8s ease-in-out infinite;
      border-radius: 30px;
    }

    @keyframes gradient {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }

    @keyframes morph {
      0% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
      50% { border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%; }
      100% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
    }

    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      border-radius: 50%;
    }

    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      background: linear-gradient(45deg,#ff0000,#ff7300,#fffb00,#48ff00,#00ffd5,#002bff,#7a00ff,#ff00c8);
      background-size: 400%;
      border-radius: 50%;
      animation: borderAnim 10s linear infinite;
      filter: blur(6px);
      z-index: -1;
    }

    @keyframes borderAnim {
      0% { background-position: 0 0; }
      50% { background-position: 400% 0; }
      100% { background-position: 0 0; }
    }

    .content {
      width: 100%;
      height: 100%;
      background-size: cover;
      background-position: center;
      border-radius: 50%;
      border: 3px solid white;
    }
  `;

  return (
    <>
      <Navbar transparent />

      <main>
        <div className="relative min-h-screen" style={{ background: connectedGradient }}>
          <div className="relative flex items-center justify-center"
               style={{ paddingTop: `${navbarHeight}px`, minHeight: "100vh" }}>

            <div className="container mx-auto px-4">

              {/* ✅ المربع الملوّن */}
              <div className="flex justify-center">
                <style>{morphingStyle}</style>

                <div className="morphing-bg text-white">

                  {/* النص */}
                  <div className="w-2/3">
                    <h2 className="text-3xl font-bold mb-4 text-green-300">
                      À propos de moi
                    </h2>

                    <p className="text-lg leading-relaxed text-gray-200">
                      Je m'appelle Yassin Abdelkader, étudiant à l'Institut Supérieur de Gestion (ISG),
                      spécialisé en Informatique Appliquée à la Gestion.
                      <br /><br />
                      Ce projet représente mon projet de fin d'études. Il consiste en la conception et le développement
                      d'un système intelligent de gestion de restaurant.
                      <br /><br />
                      À travers ce projet, j'ai appliqué mes compétences en développement web et en gestion des systèmes.
                    </p>
                  </div>

                  {/* الصورة */}
                  <div className="w-1/3 flex justify-center">
                    <div className="gradient-border-box">
                      <div
                        className="content"
                        style={{
                          backgroundImage: "url('https://graph.facebook.com/ID_FACEBOOK/picture?type=large')"
                        }}
                      ></div>
                    </div>
                  </div>

                </div>
              </div>

            </div>

          </div>
        </div>
      </main>

      <Footer />
    </>
  );
}
